const fs = require('fs');
const path = require('path');

function generatePackageLockJson() {
  const packageFile = 'package.json';
  const lockFilePath = 'package-lock.json';

  if (fs.existsSync(lockFilePath)) {
    console.log(`package-lock.json already exists, skipping generation.`);
    return;
  }

  const packageData = JSON.parse(fs.readFileSync(packageFile, 'utf8'));
  const dependencies = packageData.dependencies;

  const lockData = {};
  lockData.devDependencies = packageData.devDependencies || {};

  Object.keys(dependencies).forEach((dependency) => {
    const version = dependencies[dependency];
    lockData.dependencies = lockData.dependencies || {};
    lockData.dependencies[dependency] = version;
  });

  fs.writeFileSync(lockFilePath, JSON.stringify(lockData, null, 2));
}

